-- Program: Amazonian Strength
-- Category: Celebrity-Style -> celebrity
-- Priority: Low
-- Durations: [8, 12], Sessions: [5, 6]

-- Insert branded program
INSERT INTO branded_programs (
    name, description, category, difficulty_level,
    duration_weeks, sessions_per_week, split_type,
    goals, requires_gym, is_active
) VALUES (
    'Amazonian Strength',
    'Women''s functional power program combining strength training with athletic conditioning and flexibility.',
    'celebrity',
    'all_levels',
    12,
    6,
    'full_body',
    ARRAY['Increase maximal strength', 'Progressive overload', 'Build cardiovascular endurance', 'Improve VO2 max', 'Improve flexibility']::text[],
    true,
    true
) ON CONFLICT (name) DO UPDATE SET
    description = EXCLUDED.description,
    category = EXCLUDED.category,
    difficulty_level = EXCLUDED.difficulty_level,
    duration_weeks = EXCLUDED.duration_weeks,
    sessions_per_week = EXCLUDED.sessions_per_week,
    split_type = EXCLUDED.split_type,
    goals = EXCLUDED.goals,
    requires_gym = EXCLUDED.requires_gym,
    updated_at = NOW();

-- Variant: Amazonian Strength - 8w 5x/wk
INSERT INTO program_variants (
    base_program_id,
    intensity_level,
    duration_weeks,
    variant_name,
    program_category,
    sessions_per_week,
    session_duration_minutes,
    goals,
    workouts
) SELECT
    bp.id,
    'Medium',
    8,
    'Amazonian Strength - 8w 5x/wk',
    'celebrity',
    5,
    60,
    ARRAY['Increase maximal strength', 'Progressive overload', 'Build cardiovascular endurance', 'Improve VO2 max', 'Improve flexibility']::text[],
    '[]'::jsonb
FROM branded_programs bp
WHERE bp.name = 'Amazonian Strength'
ON CONFLICT DO NOTHING;

